var clientASNs = {};

var x = data.series[0].fields[0].values;

var y = data.series[0].fields[2].values;
var names = data.series[0].fields[1].values;

names.forEach(clientASN => {
  clientASNs[clientASN] = {
    x: [],
    y: [],
    name: clientASN,
    line: {
      width: 1
    }
  }
}); 

x.forEach((xv, i) => {
  clientASNs[names[i]].x.push(x[i]);
  clientASNs[names[i]].y.push(y[i]);
})


var data = [];
Object.keys(clientASNs).sort().forEach(clientASN => {
  data.push(clientASNs[clientASN]);
});

var trace = {
  x: x, 
  y: y, 
  name: names 
};

